drop view if exists vw_companies;
CREATE VIEW `vw_companies` AS select `tbl_companies`.`id` AS `id`,`tbl_companies`.`name` AS `name`,`tbl_companies`.`website` AS `website`,`tbl_companies`.`telephone` AS `telephone`, tbl_companies.telephone_tps, `tbl_companies`.`deleted` AS `deleted` from `tbl_companies` where (`tbl_companies`.`deleted` = 0) ;

drop view if exists vw_companies_sites;
CREATE VIEW `vw_companies_sites` AS select `c`.`id` AS `id`,`c`.`name` AS `name`,`c`.`website` AS `website`,`c`.`telephone` AS `telephone`,`c`.`telephone_tps` AS `telephone_tps`,`c`.`deleted` AS `deleted`,`s`.`id` AS `site_id`,`s`.`name` AS `site_name`,`s`.`address_1` AS `address_1`,`s`.`address_2` AS `address_2`,`s`.`town` AS `town`,`s`.`city` AS `city`,`s`.`postcode` AS `postcode`,`s`.`telephone` AS `site_telephone`,`s`.`county_id` AS `county_id`,`lkp_county`.`name` AS `county`,`s`.`country_id` AS `country_id`,`lkp_country`.`name` AS `country` from (((`tbl_companies` `c` left join `tbl_sites` `s` on((`c`.`id` = `s`.`company_id`))) left join `tbl_lkp_counties` `lkp_county` on((`lkp_county`.`id` = `s`.`county_id`))) left join `tbl_lkp_countries` `lkp_country` on((`lkp_country`.`id` = `s`.`country_id`))) where (`c`.`deleted` = 0) ;
